#!/usr/bin/env bash
# kaiju-zoo-watcher.sh — drain the KAIJU zoo queue ONE BUILD AT A TIME, across
# the full two-stage dependency (IQ-ladder feeder → KAIJU encode).
# ---------------------------------------------------------------------------
# Mirrors mistral-iq-ladder-watcher.sh's guarantees (idempotent, single-flight,
# one-encode-at-a-time), but walks an ordered queue file (kaiju-zoo-queue.txt)
# and self-drains the whole zoo. Each hourly tick, IFF no encode is in flight,
# it walks the queue and takes AT MOST ONE action on the first not-yet-done
# model:
#
#   * READY (f16 on GCS + imatrix on R2 + base knot on R2)  → submit KAIJU encode
#   * NOT READY + has a mapped HF source + not yet fed       → submit IQ-ladder
#                                                              FEEDER (mints
#                                                              f16 + imatrix)
#
# So a model with no cached f16 first gets its feeder submitted; once the feeder
# lands f16+imatrix, a later tick sees it READY and KAIJU-encodes it. Feeder and
# KAIJU are gated identically: never two encodes at once.
#
# Per-model markers (survive crashes; live in $STATE):
#   <model>.done    — KAIJU encode submitted (never re-encode)
#   <model>.feeder  — IQ-ladder feeder submitted (never re-feed; if the feeder
#                     fails, the model is skipped rather than looped — bounded)
#
# HOLD models (no HF source mapped) are skipped with a loud log — they need a
# human decision (codestral: no dense knot + only a gateway sentinel qspec;
# loki-8b: finetune source TBD; gemma4-*: GGUF source, ladder convert-path
# needs confirming). mistral-7b is EXTERNAL — its own watcher owns the feeder;
# the zoo only KAIJU-encodes it once its f16 lands.
#
# Exit codes:
#   0  = non-terminal (encode in flight, or nothing actionable this tick, locked)
#   10 = submitted one build this tick (feeder OR kaiju)
#   11 = queue fully drained (every queued, non-HOLD model has a .done marker)
#
# ENABLE (prepare-only until then):
#   cp scripts/com.forkjoin.kaiju-zoo-watcher.plist ~/Library/LaunchAgents/
#   launchctl load ~/Library/LaunchAgents/com.forkjoin.kaiju-zoo-watcher.plist
# DISABLE:
#   launchctl unload ~/Library/LaunchAgents/com.forkjoin.kaiju-zoo-watcher.plist
# ---------------------------------------------------------------------------
set -u

export PATH="/opt/homebrew/bin:/opt/homebrew/share/google-cloud-sdk/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
export CLOUDSDK_CONFIG="${CLOUDSDK_CONFIG:-/Users/buley/.config/gcloud}"
export CLOUDSDK_CORE_PROJECT="neutral-418500"

REPO="/Users/buley/Documents/Code/monorepo"
PROJECT="neutral-418500"
DI="$REPO/open-source/gnosis/distributed-inference"
SCRIPTS="$DI/scripts"
SUBMIT="$SCRIPTS/kaiju-zoo-submit.sh"
QUEUE="$SCRIPTS/kaiju-zoo-queue.txt"
STATE="$SCRIPTS/.kaiju-zoo-watcher"
LOCK="$STATE/lock.d"
LOG="$DI/IQ_ROLLOUT_LOG.md"

mkdir -p "$STATE" 2>/dev/null
log() { echo "[kaiju-zoo-watcher $(date -u +%Y-%m-%dT%H:%M:%SZ)] $*"; }

# --- per-model IQ-ladder feeder HF source ---------------------------------
# Only models with a confirmed HF safetensors source + a real argmax qspec +
# an admitted base knot are auto-feedable. Anything returning "" is HOLD (needs
# a human). "EXTERNAL" == fed by a dedicated watcher (mistral) — don't double-feed.
hf_source_of() {
  case "$1" in
    tinyllama-1.1b)   echo "TinyLlama/TinyLlama-1.1B-Chat-v1.0" ;;
    deepseek-r1-1.5b) echo "deepseek-ai/DeepSeek-R1-Distill-Qwen-1.5B" ;;
    llama-3.2-3b)     echo "meta-llama/Llama-3.2-3B-Instruct" ;;
    qwen3-4b)         echo "Qwen/Qwen3-4B" ;;
    gemma3-4b-it)     echo "google/gemma-3-4b-it" ;;
    qwen3-8b)         echo "Qwen/Qwen3-8B" ;;
    mistral-7b)       echo "EXTERNAL" ;;   # mistral-iq-ladder-watcher owns the feeder
    *)                echo "" ;;           # HOLD: loki src / gemma4 convert-path / codestral
  esac
}

# --- single-flight lock ---------------------------------------------------
if ! mkdir "$LOCK" 2>/dev/null; then
  log "STATUS=LOCKED another run holds the lock; skipping this tick"; exit 0
fi
trap 'rmdir "$LOCK" 2>/dev/null' EXIT

[ -f "$QUEUE" ] || { log "STATUS=NO_QUEUE $QUEUE missing"; exit 0; }

# --- one-encode-at-a-time gate --------------------------------------------
# An encode in flight == any ongoing build carrying a ladder _HF_SOURCE (org/repo,
# has '/') OR a knot-producing encode (_KNOT_NAME/_OUT_KEY containing 'kaiju', or
# _OUT_KEY ending '.knot'). Include _OUT_KEY: the role-mix kaiju2 build carries
# ONLY _OUT_KEY (no _HF_SOURCE/_KNOT_NAME), so keying on the latter two alone
# would go blind to it once the ladder clears → risk of a 2nd concurrent encode.
ONGOING=$(timeout 90 gcloud builds list --project "$PROJECT" --ongoing \
            --format='value(id,substitutions._HF_SOURCE,substitutions._KNOT_NAME,substitutions._OUT_KEY)' </dev/null 2>/dev/null)
if printf '%s\n' "$ONGOING" | grep -qE '[[:alnum:]_.-]+/[[:alnum:]_.-]+|kaiju|\.knot'; then
  log "STATUS=DEFER an encode is in flight:"; printf '%s\n' "$ONGOING" | sed 's/^/    /'; exit 0
fi

# --- submit helpers -------------------------------------------------------
submit_feeder() { # <model> <hf-source>  -> gcloud output on stdout
  cd "$REPO" || return 1
  timeout 3600 gcloud builds submit --config=cloudbuild-iq-ladder.yaml \
    --substitutions="_MODEL_ID=$1,_HF_SOURCE=$2,_BASELINE_GCS=" \
    --project="$PROJECT" --async --quiet . </dev/null 2>&1
}
first_uuid() { grep -oE '[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}' | head -1; }

# --- walk the queue: first actionable, not-yet-done model wins ------------
ANY_PENDING=0
while IFS= read -r line || [ -n "$line" ]; do
  MODEL="${line%%#*}"; MODEL="$(echo "$MODEL" | tr -d '[:space:]')"
  [ -z "$MODEL" ] && continue
  DONE="$STATE/$MODEL.done"
  [ -f "$DONE" ] && { log "skip $MODEL (KAIJU already submitted $(cat "$DONE"))"; continue; }
  ANY_PENDING=1

  # ---- stage 2: READY → KAIJU encode ----
  if bash "$SUBMIT" "$MODEL" --check >/dev/null 2>&1; then
    log "READY $MODEL → submitting KAIJU encode"
    OUT=$(bash "$SUBMIT" "$MODEL" --submit </dev/null 2>&1); RC=$?
    printf '%s\n' "$OUT" | sed 's/^/    /'
    NEWID=$(printf '%s\n' "$OUT" | first_uuid)
    if [ "$RC" -eq 0 ] && [ -n "$NEWID" ]; then
      echo "$NEWID  ($(date -u +%Y-%m-%dT%H:%M:%SZ))" > "$DONE"
      {
        echo ""
        echo "### $(date -u +%Y-%m-%d) — $MODEL KAIJU AUTO-SUBMITTED by kaiju-zoo-watcher"
        echo "- build \`$NEWID\` via cloudbuild-kaiju-encode.yaml (qspec-derived gate)."
        echo "  Console: https://console.cloud.google.com/cloud-build/builds/$NEWID?project=366749842679"
      } >> "$LOG" 2>/dev/null
      log "STATUS=SUBMITTED_KAIJU $MODEL build=$NEWID"; exit 10
    fi
    log "STATUS=SUBMIT_UNCERTAIN $MODEL (kaiju) rc=$RC — NOT marking done; human check"; exit 0
  fi

  # ---- stage 1: NOT READY → IQ-ladder feeder (if feedable) ----
  HF="$(hf_source_of "$MODEL")"
  if [ "$HF" = "EXTERNAL" ]; then
    log "waiting-on-external-feeder $MODEL (owned by a dedicated watcher) — retry next tick"; continue
  fi
  if [ -z "$HF" ]; then
    log "HOLD $MODEL — no HF source mapped (needs human: source / convert-path / gate). skip"; continue
  fi
  FEEDER="$STATE/$MODEL.feeder"
  if [ -f "$FEEDER" ]; then
    log "feeder-already-submitted $MODEL ($(cat "$FEEDER")) but f16 not yet READY — skip (may have failed)"; continue
  fi

  log "FEEDER $MODEL not ready → submitting IQ-ladder feeder ($HF)"
  OUT=$(submit_feeder "$MODEL" "$HF"); RC=$?
  printf '%s\n' "$OUT" | sed 's/^/    /'
  NEWID=$(printf '%s\n' "$OUT" | first_uuid)
  if [ "$RC" -eq 0 ] && [ -n "$NEWID" ]; then
    echo "$NEWID  ($(date -u +%Y-%m-%dT%H:%M:%SZ))" > "$FEEDER"
    {
      echo ""
      echo "### $(date -u +%Y-%m-%d) — $MODEL IQ-ladder FEEDER AUTO-SUBMITTED by kaiju-zoo-watcher"
      echo "- build \`$NEWID\` via cloudbuild-iq-ladder.yaml (_HF_SOURCE=$HF, self-quant ref)."
      echo "  Mints f16 + imatrix; the zoo will KAIJU-encode $MODEL once they land."
      echo "  Console: https://console.cloud.google.com/cloud-build/builds/$NEWID?project=366749842679"
    } >> "$LOG" 2>/dev/null
    log "STATUS=SUBMITTED_FEEDER $MODEL build=$NEWID"; exit 10
  fi
  log "STATUS=SUBMIT_UNCERTAIN $MODEL (feeder) rc=$RC — NOT marking fed; human check"; exit 0
done < "$QUEUE"

if [ "$ANY_PENDING" -eq 0 ]; then
  log "STATUS=DRAINED every queued model has a .done marker"; exit 11
fi
log "STATUS=NOTHING_ACTIONABLE pending models exist but none actionable this tick"; exit 0
